    // Resolve ref (commit hash or branch)
    std::string commit = resolve_ref(ref);
    if (commit.empty())
        error("unknown ...");
    // read commit manifest, overwrite files in cwd with those from commit
    restore_files_from_commit(commit);
    // handle HEAD/branch point updates as per your spec
}

void MiniGit::reset(const std::string& commit_hash) {
    if (!commit_exists(commit_hash))
        error("...");
    // Move pointer for the current branch to this commit
    update_current_branch_pointer(commit_hash);
    // (optionally restore files, if required by spec)
